// ─── Legacy STATIC_SITES for backward compatibility (map markers etc.) ─────────
export const STATIC_SITES: TourSite[] = DESTINATIONS.map((d, i) => ({
  id: i + 1,
  slug: d.slug,
  nameEn: d.nameEn,
  nameAl: d.nameAl,
  nameGr: d.nameGr,
  descEn: d.descEn,
  descAl: d.descAl,
  descGr: d.descGr,
  audioUrlEn: null, audioUrlAl: null, audioUrlGr: null,
  lat: d.lat,
  lng: d.lng,
  region: d.region,
  category: d.category,
  difficulty: "easy" as const,
  points: d.totalPoints,
  imageUrl: d.imageUrl,
  visitDuration: 120,
  funFactEn: null, funFactAl: null, funFactGr: null,
}));

// ─── Helper to get attractions for a destination ─────────────────────────────
export function getAttractions(destinationSlug: string): Attraction[] {
  return ATTRACTIONS.filter(a => a.destinationSlug === destinationSlug);
}
